BEGIN



  if coalesce(trim(both NEW.entry_id)::text, '') = ''  then
    NEW.entry_id  := pka_com_function.fp_login_id;
  end if;
  if coalesce(trim(both NEW.entry_pc)::text, '') = ''  then
    NEW.entry_pc  := pka_com_function.fp_login_pc;
  end if;
  if coalesce(trim(both NEW.entry_br)::text, '') = ''  then
    NEW.entry_br  := pka_com_function.fp_login_br;
  end if;
  if coalesce(trim(both NEW.entry_date)::text, '') = ''  then
    NEW.entry_date  := statement_timestamp();
  end if;

  if coalesce(NEW.insurance_approve::text, '') = '' then
     NEW.insurance_approve := 0;
  end if;

  if coalesce(NEW.cancel_status::text, '') = '' then
     NEW.cancel_status := 0;
  end if;

  if coalesce(NEW.insurance_balance::text, '') = '' then
     NEW.insurance_balance := 0;
  end if;

  if coalesce(NEW.insurance_arrear::text, '') = '' then
     NEW.insurance_arrear := 0;
  end if;

  if coalesce(NEW.insurance_arrear_old::text, '') = '' then
     NEW.insurance_arrear_old := 0;
  end if;


  if coalesce(NEW.last_period::text, '') = '' then
      NEW.last_period := 0;
  end if;

  if coalesce(NEW.calc_insurance::text, '') = '' then
      NEW.calc_insurance := 0;
  end if;

  if coalesce(NEW.latest_insurance_cost::text, '') = '' then
      NEW.latest_insurance_cost := 0;
  end if;

  if coalesce(NEW.BEGINing_of_contract::text, '') = '' then
    NEW.BEGINing_of_contract := to_date(statement_timestamp(),'dd/mm/yyyy');
  end if;

  if coalesce(NEW.start_keep_date::text, '') = '' then
    NEW.start_keep_date := to_date(statement_timestamp(),'dd/mm/yyyy');
  end if;

  if coalesce(NEW.company_send_status::text, '') = '' then
    NEW.company_send_status := '2';
  end if;

  if coalesce(NEW.company_send_amount::text, '') = '' then
    NEW.company_send_amount := 0;
  end if;

  if coalesce(NEW.company_return::text, '') = '' then
    NEW.company_return := 0;
  end if;

  if coalesce(NEW.company_add::text, '') = '' then
    NEW.company_add := 0;
  end if;


  if coalesce(trim(both NEW.company_status)::text, '') = ''  then
    NEW.company_status  := '0';
  end if;

  if coalesce(trim(both NEW.insurance_status)::text, '') = ''  then
    NEW.insurance_status  := '0';
  end if;

  if coalesce(trim(both NEW.drop_payment)::text, '') = ''  then
    NEW.drop_payment  := '0';
  end if;

  if coalesce(NEW.post_to_fin::text, '') = '' then
    NEW.post_to_fin := '0';
  end if;

  --จำนวนกรมธรรม์
  if coalesce(NEW.count_krom::text, '') = '' then
    NEW.count_krom := 1;
  end if;

  --สถานะการต่อกรมธรรม์
  if coalesce(NEW.calc_continue::text, '') = '' then
    NEW.calc_continue := '2';
  end if;

  --ทุนประกันที่ต้องต่อใหม่
  if coalesce(NEW.calc_insurance_cost::text, '') = '' then
    NEW.calc_insurance_cost := 0;
  end if;

  --เบี้ยประกันที่ต้องต่อใหม่
  if coalesce(NEW.calc_insurance::text, '') = '' then
    NEW.calc_insurance := 0;
  end if;

--  --ยกเลิกสัญญาให้ไปยกเลิกคำขอด้วย
--  if :new.cancel_status = 1 then
--    update sc_mem_m_insure_req
--    set approve_status ='0'
--    where insurance_type = :new.insurance_type
--    and membership_no = :new.membership_no
--    and insure_year = :new.insure_year
--   ;
--  end if ;
  
    --ประกันรอนำส่งคงที่
  if coalesce(NEW.insurance_money_waiting::text, '') = '' then
    NEW.insurance_money_waiting := 0;
  end if;

  --ประกันรอนำส่ง
  if coalesce(NEW.insurance_money_wait_bal::text, '') = '' then
    NEW.insurance_money_wait_bal := 0;
  end if;



RETURN NEW;
end
